const ALLOWED_LANGS=["en","ru","hy"];async function setLanguage(e){if(!ALLOWED_LANGS.includes(e))return;const t=await fetch(`../../data/${e}.json`);if(!t.ok)return;const n=await t.json();document.getElementById("page-title").textContent=n.pageTitle,document.getElementById("page-description").textContent=n.pageDescription,document.getElementById("label-service").textContent=n.labelService,document.getElementById("label-description").textContent=n.labelDescription,document.getElementById("submit-button").textContent=n.submitButton,currentLangData=n,updateTotal()}let currentLangData=null;const prices={document:1,website:2,subtitles:3,certified:5,interpretation:10,other:0};function updateTotal(){const e=document.querySelectorAll('select[name="service"]');let t=0;e.forEach(e=>{t+=prices[e.value]||0});const n=currentLangData?.totalPrice||"Your total price is: $";document.getElementById("total-price").textContent=n+t}function addRequest(e){const t=document.getElementById("requests-container"),n=document.querySelector(".request-block").cloneNode(!0);n.querySelector("textarea").value="";const o=n.querySelector("select");o.selectedIndex=0,o.addEventListener("change",updateTotal);const a=n.querySelector(".request-buttons"),c=document.createElement("button");c.type="button",c.className="add-btn",c.textContent="+",c.addEventListener("click",()=>addRequest(c));const r=document.createElement("button");for(r.type="button",r.className="remove-btn",r.textContent="−",r.addEventListener("click",()=>removeRequest(r));a.firstChild;)a.removeChild(a.firstChild);a.appendChild(c),a.appendChild(r),t.appendChild(n),updateTotal()}function removeRequest(e){e.closest(".request-block").remove(),updateTotal()}function redirectSubmit(){const e=document.querySelectorAll('textarea[name="description"]');Array.from(e).some(e=>e.value.trim().length>0)?document.getElementById("request-form").submit():alert(currentLangData?.validationError||"Please describe at least one request.")}window.onload=()=>{setLanguage("en"),document.querySelectorAll(".lang-icon[data-lang]").forEach(e=>{e.addEventListener("click",()=>setLanguage(e.dataset.lang))}),document.getElementById("submit-button").addEventListener("click",redirectSubmit),document.querySelector(".request-buttons .add-btn").addEventListener("click",function(){addRequest(this)}),document.querySelector('select[name="service"]').addEventListener("change",updateTotal)};